def networkDelayTime(times, n, k):
    g = {i: [] for i in range(1, n+1)}
    for u, v, w in times:
        g[u].append((v, w))
    dist = {}
    heap = [(0, k)]
    while heap:
        d, u = heapq.heappop(heap)
        if u in dist:
            continue
        dist[u] = d
        for v, w in g[u]:
            if v not in dist:
                heapq.heappush(heap, (d+w, v))
    return max(dist.values()) if len(dist) == n else -1

